import{_ as e,o as r,c as a,a7 as o}from"./chunks/framework.C5fSpjcB.js";const u=JSON.parse('{"title":"Main Story","description":"","frontmatter":{},"headers":[],"relativePath":"en/story/main.md","filePath":"en/story/main.md","lastUpdated":1775394001000}'),d={name:"en/story/main.md"};function s(i,t,h,n,l,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="main-story" tabindex="-1">Main Story <a class="header-anchor" href="#main-story" aria-label="Permalink to &quot;Main Story&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">Spoiler Warning</p><p>The following content contains spoilers for the main storyline of Morimens. Read at your own discretion.</p></div><p>The main story of Morimens spans approximately <strong>800,000 Chinese characters</strong> of text across two major arcs and follows the Keeper&#39;s journey through a world haunted by Lovecraftian horrors. New chapters are added with major updates.</p><h2 id="arc-1-oblivion-chapter" tabindex="-1">Arc 1: Oblivion Chapter <a class="header-anchor" href="#arc-1-oblivion-chapter" aria-label="Permalink to &quot;Arc 1: Oblivion Chapter&quot;">​</a></h2><p>The Oblivion Chapter covers the Keeper&#39;s early journey, from their arrival at Mythag University to discovering the truth behind the Erosion disaster.</p><table tabindex="0"><thead><tr><th>Chapter</th><th>Title</th><th>Notes</th></tr></thead><tbody><tr><td>Prologue</td><td>Prologue</td><td>The Keeper awakens and discovers their role at Mythag University.</td></tr><tr><td>Chapter 1</td><td>East District Secrets</td><td>Investigation deepens: workshop manager, suspicious doctor, suspected cult. The truth centers on a controlled girl who chose to end herself to protect her loved ones. Sub-chapters 1-1 through 1-10.</td></tr><tr><td>Chapter 2</td><td>Metamorphosis</td><td>Main story continues.</td></tr><tr><td>Chapter 3</td><td>Chapter 3</td><td>Main story continues.</td></tr><tr><td>Chapter 4</td><td>Chapter 4</td><td>Major turning point. Characters bring a rescued girl (Lily) to a sanatorium, only to discover a larger crisis lurking within. Player choices affect later story.</td></tr><tr><td>Chapter 5</td><td>Chapter 5</td><td>Was temporarily closed and later reopened with compensation rewards. Remade from scratch during development.</td></tr><tr><td>Chapter 6</td><td>Chapter 6</td><td>Main story continues.</td></tr><tr><td>Chapter 7</td><td>Chapter 7</td><td>Includes 7-18 &quot;Kindling&quot; and other Boss stages.</td></tr></tbody></table><h3 id="chapter-1-sub-chapters" tabindex="-1">Chapter 1 Sub-chapters <a class="header-anchor" href="#chapter-1-sub-chapters" aria-label="Permalink to &quot;Chapter 1 Sub-chapters&quot;">​</a></h3><table tabindex="0"><thead><tr><th>ID</th><th>Title (EN)</th></tr></thead><tbody><tr><td>1-1</td><td>Dream of Darkness</td></tr><tr><td>1-2</td><td>Don&#39;t Judge By Appearance</td></tr><tr><td>1-3</td><td>Underground Phantom</td></tr><tr><td>1-4</td><td>Little Detective</td></tr><tr><td>1-5</td><td>Illness</td></tr><tr><td>1-6</td><td>Speak No Evil</td></tr><tr><td>1-7</td><td>Who Killed the Robin?</td></tr><tr><td>1-8</td><td>Inner Danger</td></tr><tr><td>1-9</td><td>Our Secret</td></tr><tr><td>1-10</td><td>The Sweet Art</td></tr></tbody></table><h2 id="arc-2-stellar-chapter" tabindex="-1">Arc 2: Stellar Chapter <a class="header-anchor" href="#arc-2-stellar-chapter" aria-label="Permalink to &quot;Arc 2: Stellar Chapter&quot;">​</a></h2><p>The Stellar Chapter begins with v2.0 and introduces new systems including Key Orders, mixed-realm team building, and the Chaos realm rework.</p><table tabindex="0"><thead><tr><th>Chapter</th><th>Title</th><th>Stages</th><th>Notes</th></tr></thead><tbody><tr><td>Prologue</td><td>Stellar Prologue</td><td>—</td><td>Opening of the Stellar Chapter.</td></tr><tr><td>Chapter 1</td><td>Stellar Chapter 1</td><td>1-1 to 1-14</td><td>First chapter of the Stellar arc.</td></tr><tr><td>Chapter 2</td><td>Metamorphosis</td><td>2-1 to 2-18</td><td>Stellar Chapter 2.</td></tr><tr><td>Chapter 3</td><td>Stellar Chapter 3</td><td>3-1 to 3-11</td><td>Stellar Chapter 3.</td></tr><tr><td>Chapter 4</td><td>Paradise</td><td>4-0 to 4-16</td><td>Largest difficulty spike chapter. &quot;Why has the black sun covered the sky?&quot;</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Chapter 5 of the Oblivion Chapter was remade from scratch during development. Players who experienced the original version should replay it for the updated story.</p></div><h2 id="late-game-story-mechanics" tabindex="-1">Late-Game Story Mechanics <a class="header-anchor" href="#late-game-story-mechanics" aria-label="Permalink to &quot;Late-Game Story Mechanics&quot;">​</a></h2><h3 id="erosion-black-tide" tabindex="-1">Erosion Black Tide <a class="header-anchor" href="#erosion-black-tide" aria-label="Permalink to &quot;Erosion Black Tide&quot;">​</a></h3><p>Later chapters introduce the <strong>Erosion Black Tide</strong> -- a special negative effect system that includes debuffs such as &quot;Aliemus Decay&quot; and &quot;Silver Key Oscillation&quot; that alter combat dynamics.</p><h2 id="key-story-themes" tabindex="-1">Key Story Themes <a class="header-anchor" href="#key-story-themes" aria-label="Permalink to &quot;Key Story Themes&quot;">​</a></h2><ul><li><strong>The Keeper&#39;s Promise</strong> -- The player vows to preserve and protect the Awakeners, even as they are sent into increasingly dangerous situations.</li><li><strong>The Nature of Madness</strong> -- As the story progresses, the line between sanity and madness blurs for both the Keeper and the Awakeners.</li><li><strong>Eldritch Truth</strong> -- Each chapter reveals more about the cosmic forces at work behind the world&#39;s surface.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./">Story &amp; Lore Overview</a></li><li><a href="./character-stories.html">Character Stories</a></li><li><a href="./worldbuilding.html">Worldbuilding</a></li><li><a href="./../stages/main.html">Main Stages</a></li></ul>',19)])])}const m=e(d,[["render",s]]);export{u as __pageData,m as default};
